package tree

import "time"

// NodeType represents the type of knowledge artifact
type NodeType string

const (
	NodeTypeInvestigation NodeType = "investigation"
	NodeTypeDecision      NodeType = "decision"
	NodeTypeModel         NodeType = "model"
	NodeTypeProbe         NodeType = "probe"
	NodeTypeGuide         NodeType = "guide"
	NodeTypeIssue         NodeType = "issue"
	NodeTypeCluster       NodeType = "cluster"
	NodeTypePostMortem    NodeType = "postmortem"
	NodeTypeHandoff       NodeType = "handoff"
)

// NodeStatus represents the status of a node (for investigations and issues)
type NodeStatus string

const (
	StatusComplete    NodeStatus = "complete"
	StatusTriage      NodeStatus = "triage"
	StatusInProgress  NodeStatus = "in_progress"
	StatusClosed      NodeStatus = "closed"
	StatusOpen        NodeStatus = "open"
)

// KnowledgeNode represents a node in the knowledge tree
type KnowledgeNode struct {
	ID       string                 // Unique identifier (file path or beads ID)
	Type     NodeType               // Type of node
	Title    string                 // Display title
	Path     string                 // File path (for file-based artifacts) or beads ID (for issues)
	Status   NodeStatus             // Status (if applicable)
	Date     time.Time              // Creation or update date
	Children []*KnowledgeNode       // Child nodes
	Metadata map[string]interface{} // Additional metadata
}

// Relationship represents a relationship between artifacts
type Relationship struct {
	From         string // Source file path
	To           string // Target file path
	RelationType string // Type of relationship (synthesizes, references, extends, etc.)
	Verified     bool   // Whether the relationship was verified
}

// Cluster represents a group of related artifacts
type Cluster struct {
	Name  string            // Cluster name
	Nodes []*KnowledgeNode  // Nodes in this cluster
}

// TreeOptions represents options for rendering the tree
type TreeOptions struct {
	ClusterFilter string // Filter to specific cluster
	Depth         int    // Maximum depth to render (0 = unlimited)
	Format        string // Output format (text or json)
	WorkView      bool   // Use work view instead of knowledge view
}

package tree

import (
	"bufio"
	"fmt"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"time"
)

var (
	// Prior-Work table row pattern: | path | relationship | verified | conflicts |
	priorWorkRowRegex = regexp.MustCompile(`^\|\s*(.+?)\s*\|\s*(.+?)\s*\|\s*(.+?)\s*\|`)

	// Synthesized From header pattern
	synthesizedFromRegex = regexp.MustCompile(`(?i)^\*\*Synthesized From:\*\*\s*(.+)$`)

	// Status field pattern
	statusRegex = regexp.MustCompile(`(?i)^\*\*Status:\*\*\s*(.+)$`)

	// Date field pattern
	dateRegex = regexp.MustCompile(`(?i)^\*\*(?:Started|Date|Updated):\*\*\s*(.+)$`)
)

// ParseInvestigations parses all investigation files in a directory
func ParseInvestigations(dir string) ([]*KnowledgeNode, []Relationship, error) {
	var nodes []*KnowledgeNode
	var relationships []Relationship

	err := filepath.Walk(dir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		if info.IsDir() || !strings.HasSuffix(path, ".md") {
			return nil
		}

		node, rels, err := parseInvestigation(path)
		if err != nil {
			// Log error but continue parsing other files
			fmt.Fprintf(os.Stderr, "Warning: failed to parse %s: %v\n", path, err)
			return nil
		}

		if node != nil {
			nodes = append(nodes, node)
			relationships = append(relationships, rels...)
		}

		return nil
	})

	return nodes, relationships, err
}

// parseInvestigation parses a single investigation file
func parseInvestigation(path string) (*KnowledgeNode, []Relationship, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, nil, err
	}
	defer file.Close()

	node := &KnowledgeNode{
		ID:       path,
		Type:     NodeTypeInvestigation,
		Path:     path,
		Status:   StatusComplete, // Default status
		Metadata: make(map[string]interface{}),
	}

	var relationships []Relationship
	scanner := bufio.NewScanner(file)
	inPriorWork := false
	lineNum := 0

	for scanner.Scan() {
		line := scanner.Text()
		lineNum++

		// Extract title from first heading
		if lineNum < 50 && strings.HasPrefix(line, "# ") && node.Title == "" {
			node.Title = strings.TrimPrefix(line, "# ")
			node.Title = strings.TrimPrefix(node.Title, "Investigation: ")
			continue
		}

		// Extract status
		if matches := statusRegex.FindStringSubmatch(line); matches != nil {
			status := strings.ToLower(strings.TrimSpace(matches[1]))
			switch status {
			case "complete", "completed":
				node.Status = StatusComplete
			case "triage", "triage:review":
				node.Status = StatusTriage
			case "in progress", "in_progress", "active":
				node.Status = StatusInProgress
			}
			continue
		}

		// Extract date
		if matches := dateRegex.FindStringSubmatch(line); matches != nil {
			if date, err := time.Parse("2006-01-02", strings.TrimSpace(matches[1])); err == nil {
				node.Date = date
			}
			continue
		}

		// Check for Prior-Work section
		if strings.Contains(line, "**Prior-Work:**") || strings.Contains(line, "## Prior Work") {
			inPriorWork = true
			continue
		}

		// End of Prior-Work section
		if inPriorWork && (strings.HasPrefix(line, "##") || strings.HasPrefix(line, "---")) {
			inPriorWork = false
			continue
		}

		// Parse Prior-Work table rows
		if inPriorWork {
			if matches := priorWorkRowRegex.FindStringSubmatch(line); matches != nil && len(matches) > 2 {
				targetPath := strings.TrimSpace(matches[1])
				relType := strings.TrimSpace(matches[2])
				verified := strings.TrimSpace(matches[3])

				// Skip table header row
				if targetPath == "Investigation" || targetPath == "---" {
					continue
				}

				relationships = append(relationships, Relationship{
					From:         path,
					To:           targetPath,
					RelationType: relType,
					Verified:     strings.ToLower(verified) == "yes",
				})
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return nil, nil, err
	}

	return node, relationships, nil
}

// ParseDecisions parses all decision files in a directory
func ParseDecisions(dir string) ([]*KnowledgeNode, []Relationship, error) {
	var nodes []*KnowledgeNode
	var relationships []Relationship

	err := filepath.Walk(dir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		if info.IsDir() || !strings.HasSuffix(path, ".md") {
			return nil
		}

		node, rels, err := parseDecision(path)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Warning: failed to parse %s: %v\n", path, err)
			return nil
		}

		if node != nil {
			nodes = append(nodes, node)
			relationships = append(relationships, rels...)
		}

		return nil
	})

	return nodes, relationships, err
}

// parseDecision parses a single decision file
func parseDecision(path string) (*KnowledgeNode, []Relationship, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, nil, err
	}
	defer file.Close()

	node := &KnowledgeNode{
		ID:       path,
		Type:     NodeTypeDecision,
		Path:     path,
		Metadata: make(map[string]interface{}),
	}

	var relationships []Relationship
	scanner := bufio.NewScanner(file)
	lineNum := 0

	for scanner.Scan() {
		line := scanner.Text()
		lineNum++

		// Extract title from first heading
		if lineNum < 50 && strings.HasPrefix(line, "# ") && node.Title == "" {
			node.Title = strings.TrimPrefix(line, "# ")
			node.Title = strings.TrimPrefix(node.Title, "Decision: ")
			continue
		}

		// Extract date
		if matches := dateRegex.FindStringSubmatch(line); matches != nil {
			if date, err := time.Parse("2006-01-02", strings.TrimSpace(matches[1])); err == nil {
				node.Date = date
			}
			continue
		}

		// Extract references to investigations in Evidence section
		// Look for markdown links: [text](.kb/investigations/file.md)
		refRegex := regexp.MustCompile(`\[.+?\]\((.kb/investigations/.+?\.md)\)`)
		if matches := refRegex.FindAllStringSubmatch(line, -1); matches != nil {
			for _, match := range matches {
				if len(match) > 1 {
					relationships = append(relationships, Relationship{
						From:         path,
						To:           match[1],
						RelationType: "references",
						Verified:     true,
					})
				}
			}
		}
	}

	if err := scanner.Err(); err != nil {
		return nil, nil, err
	}

	return node, relationships, nil
}

// ParseModels parses all model directories
func ParseModels(dir string) ([]*KnowledgeNode, []Relationship, error) {
	var nodes []*KnowledgeNode
	var relationships []Relationship

	entries, err := os.ReadDir(dir)
	if err != nil {
		return nil, nil, err
	}

	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}

		modelPath := filepath.Join(dir, entry.Name())
		modelFile := filepath.Join(modelPath, entry.Name()+".md")

		// Check if the model file exists
		if _, err := os.Stat(modelFile); os.IsNotExist(err) {
			continue
		}

		node, rels, err := parseModel(modelFile, modelPath)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Warning: failed to parse %s: %v\n", modelFile, err)
			continue
		}

		if node != nil {
			nodes = append(nodes, node)
			relationships = append(relationships, rels...)

			// Parse probes for this model
			probesDir := filepath.Join(modelPath, "probes")
			if probes, probeRels, err := ParseProbes(probesDir, node.ID); err == nil {
				node.Children = append(node.Children, probes...)
				relationships = append(relationships, probeRels...)
			}
		}
	}

	return nodes, relationships, nil
}

// parseModel parses a single model file
func parseModel(path string, modelDir string) (*KnowledgeNode, []Relationship, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, nil, err
	}
	defer file.Close()

	node := &KnowledgeNode{
		ID:       modelDir,
		Type:     NodeTypeModel,
		Path:     path,
		Children: []*KnowledgeNode{},
		Metadata: make(map[string]interface{}),
	}

	var relationships []Relationship
	scanner := bufio.NewScanner(file)
	lineNum := 0

	for scanner.Scan() {
		line := scanner.Text()
		lineNum++

		// Extract title from first heading
		if lineNum < 50 && strings.HasPrefix(line, "# ") && node.Title == "" {
			node.Title = strings.TrimPrefix(line, "# ")
			node.Title = strings.TrimPrefix(node.Title, "Model: ")
			continue
		}

		// Extract Synthesized From header
		if matches := synthesizedFromRegex.FindStringSubmatch(line); matches != nil {
			// This indicates the model synthesizes multiple investigations
			// We could parse the investigation references here
			node.Metadata["synthesized_from"] = matches[1]
			continue
		}
	}

	if err := scanner.Err(); err != nil {
		return nil, nil, err
	}

	return node, relationships, nil
}

// ParseProbes parses all probe files for a model
func ParseProbes(dir string, modelID string) ([]*KnowledgeNode, []Relationship, error) {
	var nodes []*KnowledgeNode
	var relationships []Relationship

	if _, err := os.Stat(dir); os.IsNotExist(err) {
		return nodes, relationships, nil
	}

	err := filepath.Walk(dir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		if info.IsDir() || !strings.HasSuffix(path, ".md") {
			return nil
		}

		node, err := parseProbe(path, modelID)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Warning: failed to parse %s: %v\n", path, err)
			return nil
		}

		if node != nil {
			nodes = append(nodes, node)
			relationships = append(relationships, Relationship{
				From:         path,
				To:           modelID,
				RelationType: "probes",
				Verified:     true,
			})
		}

		return nil
	})

	return nodes, relationships, err
}

// parseProbe parses a single probe file
func parseProbe(path string, modelID string) (*KnowledgeNode, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	node := &KnowledgeNode{
		ID:       path,
		Type:     NodeTypeProbe,
		Path:     path,
		Metadata: make(map[string]interface{}),
	}
	node.Metadata["model_id"] = modelID

	scanner := bufio.NewScanner(file)
	lineNum := 0

	for scanner.Scan() {
		line := scanner.Text()
		lineNum++

		// Extract title from first heading
		if lineNum < 50 && strings.HasPrefix(line, "# ") && node.Title == "" {
			node.Title = strings.TrimPrefix(line, "# ")
			node.Title = strings.TrimPrefix(node.Title, "Probe: ")
			break
		}
	}

	if err := scanner.Err(); err != nil {
		return nil, err
	}

	// Use filename as title if no title found
	if node.Title == "" {
		node.Title = filepath.Base(path)
		node.Title = strings.TrimSuffix(node.Title, ".md")
	}

	return node, nil
}

// ParseGuides parses all guide files in a directory
func ParseGuides(dir string) ([]*KnowledgeNode, error) {
	var nodes []*KnowledgeNode

	err := filepath.Walk(dir, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		if info.IsDir() || !strings.HasSuffix(path, ".md") {
			return nil
		}

		node, err := parseGuide(path)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Warning: failed to parse %s: %v\n", path, err)
			return nil
		}

		if node != nil {
			nodes = append(nodes, node)
		}

		return nil
	})

	return nodes, err
}

// parseGuide parses a single guide file
func parseGuide(path string) (*KnowledgeNode, error) {
	file, err := os.Open(path)
	if err != nil {
		return nil, err
	}
	defer file.Close()

	node := &KnowledgeNode{
		ID:       path,
		Type:     NodeTypeGuide,
		Path:     path,
		Metadata: make(map[string]interface{}),
	}

	scanner := bufio.NewScanner(file)
	lineNum := 0

	for scanner.Scan() {
		line := scanner.Text()
		lineNum++

		// Extract title from first heading
		if lineNum < 50 && strings.HasPrefix(line, "# ") && node.Title == "" {
			node.Title = strings.TrimPrefix(line, "# ")
			break
		}
	}

	if err := scanner.Err(); err != nil {
		return nil, err
	}

	// Use filename as title if no title found
	if node.Title == "" {
		node.Title = filepath.Base(path)
		node.Title = strings.TrimSuffix(node.Title, ".md")
	}

	return node, nil
}

package tree

import (
	"os"
	"path/filepath"
	"strings"
)

// DetectClusters detects clusters from filesystem organization
func DetectClusters(kbDir string, nodes []*KnowledgeNode, relationships []Relationship) ([]*Cluster, error) {
	clusters := make(map[string]*Cluster)

	// 1. Filesystem-based clustering from investigations/synthesized/{cluster}/
	synthesizedDir := filepath.Join(kbDir, "investigations", "synthesized")
	if entries, err := os.ReadDir(synthesizedDir); err == nil {
		for _, entry := range entries {
			if !entry.IsDir() {
				continue
			}

			clusterName := entry.Name()
			clusters[clusterName] = &Cluster{
				Name:  clusterName,
				Nodes: []*KnowledgeNode{},
			}
		}
	}

	// 2. Assign nodes to clusters based on their path
	for _, node := range nodes {
		// Check if node is in a synthesized subdirectory
		if strings.Contains(node.Path, "/investigations/synthesized/") {
			parts := strings.Split(node.Path, "/investigations/synthesized/")
			if len(parts) > 1 {
				clusterName := strings.Split(parts[1], "/")[0]
				if cluster, ok := clusters[clusterName]; ok {
					cluster.Nodes = append(cluster.Nodes, node)
					continue
				}
			}
		}

		// If not in a cluster, assign to "uncategorized"
		if _, ok := clusters["uncategorized"]; !ok {
			clusters["uncategorized"] = &Cluster{
				Name:  "uncategorized",
				Nodes: []*KnowledgeNode{},
			}
		}
		clusters["uncategorized"].Nodes = append(clusters["uncategorized"].Nodes, node)
	}

	// Convert map to slice
	var result []*Cluster
	for _, cluster := range clusters {
		if len(cluster.Nodes) > 0 {
			result = append(result, cluster)
		}
	}

	return result, nil
}

// BuildRelationshipGraph builds a graph of nodes connected by relationships
func BuildRelationshipGraph(nodes []*KnowledgeNode, relationships []Relationship) map[string][]*KnowledgeNode {
	graph := make(map[string][]*KnowledgeNode)
	nodeMap := make(map[string]*KnowledgeNode)

	// Index nodes by their path
	for _, node := range nodes {
		nodeMap[node.Path] = node
	}

	// Build parent-child relationships
	for _, rel := range relationships {
		parent, parentExists := nodeMap[rel.From]
		child, childExists := nodeMap[rel.To]

		if parentExists && childExists {
			// Add child to parent's children if not already there
			found := false
			for _, existingChild := range parent.Children {
				if existingChild.ID == child.ID {
					found = true
					break
				}
			}
			if !found {
				parent.Children = append(parent.Children, child)
			}

			// Track in graph
			graph[parent.ID] = append(graph[parent.ID], child)
		}
	}

	return graph
}

package tree

import (
	"encoding/json"
	"fmt"
	"path/filepath"
	"strings"
)

// Icon constants for different node types
const (
	IconInvestigationComplete = "◉"
	IconInvestigationTriage   = "◇"
	IconInvestigationProgress = "●"
	IconDecision              = "★"
	IconModel                 = "◆"
	IconGuide                 = "◈"
	IconIssue                 = "●"
	IconCluster               = "◉"
)

// getNodeIcon returns the icon for a node based on its type and status
func getNodeIcon(node *KnowledgeNode) string {
	switch node.Type {
	case NodeTypeDecision:
		return IconDecision
	case NodeTypeModel:
		return IconModel
	case NodeTypeGuide:
		return IconGuide
	case NodeTypeIssue:
		return IconIssue
	case NodeTypeCluster:
		return IconCluster
	case NodeTypeInvestigation:
		switch node.Status {
		case StatusComplete:
			return IconInvestigationComplete
		case StatusTriage:
			return IconInvestigationTriage
		case StatusInProgress:
			return IconInvestigationProgress
		default:
			return IconInvestigationComplete
		}
	default:
		return "◉"
	}
}

// getNodeTitle returns the display title for a node
func getNodeTitle(node *KnowledgeNode) string {
	if node.Title != "" {
		return node.Title
	}
	// Fallback to filename without extension
	base := filepath.Base(node.Path)
	return strings.TrimSuffix(base, filepath.Ext(base))
}

// getNodeStatus returns the status label for display
func getNodeStatus(node *KnowledgeNode) string {
	switch node.Status {
	case StatusComplete:
		return "CLOSED"
	case StatusTriage:
		return "triage:review"
	case StatusInProgress:
		return "IN PROGRESS"
	case StatusClosed:
		return "CLOSED"
	case StatusOpen:
		return "OPEN"
	default:
		return ""
	}
}

// RenderTree renders the tree as ASCII text
func RenderTree(root *KnowledgeNode, opts TreeOptions) (string, error) {
	if opts.Format == "json" {
		return renderJSON(root)
	}

	var sb strings.Builder
	sb.WriteString("orch-go knowledge tree\n")
	sb.WriteString("│\n")

	renderNode(&sb, root, "", true, 0, opts.Depth)

	return sb.String(), nil
}

// renderJSON renders the tree as JSON
func renderJSON(root *KnowledgeNode) (string, error) {
	data, err := json.MarshalIndent(root, "", "  ")
	if err != nil {
		return "", err
	}
	return string(data), nil
}

// renderNode renders a single node and its children recursively
func renderNode(sb *strings.Builder, node *KnowledgeNode, prefix string, isLast bool, currentDepth int, maxDepth int) {
	if maxDepth > 0 && currentDepth >= maxDepth {
		return
	}

	// Skip root node
	if node.Type == NodeTypeCluster || currentDepth == 0 {
		// Render cluster header or root
		if currentDepth > 0 {
			connector := "├─"
			if isLast {
				connector = "└─"
			}
			sb.WriteString(prefix)
			sb.WriteString(connector)
			sb.WriteString(getNodeIcon(node))
			sb.WriteString(" ")
			sb.WriteString(getNodeTitle(node))
			sb.WriteString("\n")
		}

		// Render children
		for i, child := range node.Children {
			childIsLast := i == len(node.Children)-1
			childPrefix := prefix
			if currentDepth > 0 {
				if isLast {
					childPrefix += "  "
				} else {
					childPrefix += "│ "
				}
			}
			renderNode(sb, child, childPrefix, childIsLast, currentDepth+1, maxDepth)
		}
		return
	}

	// Render regular node
	connector := "├─"
	if isLast {
		connector = "└─"
	}

	sb.WriteString(prefix)
	sb.WriteString(connector)
	sb.WriteString(getNodeIcon(node))
	sb.WriteString(" ")

	// For investigations/decisions, show path relative to .kb/
	if node.Type == NodeTypeInvestigation || node.Type == NodeTypeDecision || node.Type == NodeTypeModel {
		// Show relative path
		if strings.Contains(node.Path, "/.kb/") {
			parts := strings.Split(node.Path, "/.kb/")
			if len(parts) > 1 {
				sb.WriteString(parts[1])
			} else {
				sb.WriteString(filepath.Base(node.Path))
			}
		} else {
			sb.WriteString(filepath.Base(node.Path))
		}
	} else if node.Type == NodeTypeIssue {
		// For issues, show ID and title
		sb.WriteString(node.ID)
		sb.WriteString("  ")
		sb.WriteString(getNodeTitle(node))

		// Add status if present
		if status := getNodeStatus(node); status != "" {
			// Pad to align status (approximate)
			titleLen := len(getNodeTitle(node))
			padding := 40 - titleLen
			if padding < 1 {
				padding = 1
			}
			sb.WriteString(strings.Repeat(" ", padding))
			sb.WriteString(status)
		}
	} else {
		sb.WriteString(getNodeTitle(node))
	}

	sb.WriteString("\n")

	// Render children
	for i, child := range node.Children {
		childIsLast := i == len(node.Children)-1
		childPrefix := prefix
		if isLast {
			childPrefix += "  "
		} else {
			childPrefix += "│ "
		}
		renderNode(sb, child, childPrefix, childIsLast, currentDepth+1, maxDepth)
	}
}

// RenderWorkView renders the tree in work view (issues as primary nodes)
func RenderWorkView(issues []*KnowledgeNode, opts TreeOptions) (string, error) {
	if opts.Format == "json" {
		return renderJSON(&KnowledgeNode{
			Type:     NodeTypeCluster,
			Title:    "work-view",
			Children: issues,
		})
	}

	var sb strings.Builder
	sb.WriteString("orch-go work tree\n")
	sb.WriteString("│\n")

	// Group issues by status
	statusGroups := make(map[NodeStatus][]*KnowledgeNode)
	for _, issue := range issues {
		statusGroups[issue.Status] = append(statusGroups[issue.Status], issue)
	}

	// Render each status group
	statusOrder := []NodeStatus{StatusInProgress, StatusTriage, StatusOpen, StatusClosed}
	groupIndex := 0
	totalGroups := 0
	for _, status := range statusOrder {
		if len(statusGroups[status]) > 0 {
			totalGroups++
		}
	}

	for _, status := range statusOrder {
		group := statusGroups[status]
		if len(group) == 0 {
			continue
		}

		groupIndex++
		isLastGroup := groupIndex == totalGroups

		// Render group header
		connector := "├─"
		if isLastGroup {
			connector = "└─"
		}

		statusLabel := getStatusLabel(status)
		sb.WriteString(connector)
		sb.WriteString(statusLabel)
		sb.WriteString(fmt.Sprintf(" (%d)\n", len(group)))

		// Render issues in group
		for i, issue := range group {
			isLast := i == len(group)-1
			prefix := ""
			if !isLastGroup {
				prefix = "│ "
			} else {
				prefix = "  "
			}

			issueConnector := "├─"
			if isLast {
				issueConnector = "└─"
			}

			sb.WriteString(prefix)
			sb.WriteString(issueConnector)
			sb.WriteString(getNodeIcon(issue))
			sb.WriteString(" ")
			sb.WriteString(issue.ID)
			sb.WriteString("  ")
			sb.WriteString(getNodeTitle(issue))
			sb.WriteString("\n")

			// Render knowledge artifacts as children
			for j, child := range issue.Children {
				childIsLast := j == len(issue.Children)-1
				childPrefix := prefix
				if isLast {
					childPrefix += "  "
				} else {
					childPrefix += "│ "
				}

				childConnector := "├─"
				if childIsLast {
					childConnector = "└─"
				}

				sb.WriteString(childPrefix)
				sb.WriteString(childConnector)
				sb.WriteString(" from ")
				sb.WriteString(getNodeIcon(child))
				sb.WriteString(" ")
				sb.WriteString(filepath.Base(child.Path))
				sb.WriteString("\n")
			}
		}
	}

	return sb.String(), nil
}

// getStatusLabel returns the display label for a status
func getStatusLabel(status NodeStatus) string {
	switch status {
	case StatusInProgress:
		return "● IN PROGRESS"
	case StatusTriage:
		return "◇ TRIAGE:REVIEW"
	case StatusOpen:
		return "◐ QUEUED"
	case StatusClosed:
		return "◓ COMPLETED"
	default:
		return "● " + string(status)
	}
}

